class Solution {
    public int minSwaps(String s) {
        int n = s.length();
        int openCount = 0;
        int swaps = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '[') {
                openCount++;
            } else {
                if (openCount > 0) {
                    openCount--;
                } else {
                    swaps++;
                }
            }
        }
        return swaps;
    }
}
```
